#!/usr/bin/env python3
import os,sys,json,time,subprocess
def sh(c,t=20):
    try:
        r=subprocess.run(["bash","-lc",c],capture_output=True,text=True,timeout=t);return (r.stdout+r.stderr).strip()
    except Exception: return "ERR"
def psql(q,t=15):
    r=subprocess.run(["sudo","-u","postgres","psql","tuanichat_atlas","-tAc",q],capture_output=True,text=True,timeout=t)
    return (r.stdout.strip() if r.returncode==0 else "ERR")
out={"kind":"discflow","ts":int(time.time())}
F="/opt/atlas/importers/atlas_source_discovery.py"
try:
    out["catalog_states"]=psql("SELECT state||':'||count(*) FROM atlas.source_catalog GROUP BY state ORDER BY 2 DESC")
    out["approved_sample"]=psql("SELECT source_key||'|'||left(coalesce(name,''),30)||'|p='||round(wiring_priority::numeric,3) FROM atlas.source_catalog WHERE state IN ('APPROVED','SOURCE_APPROVED','WIRED') ORDER BY wiring_priority DESC LIMIT 8")
    out["disc_active"]=sh("systemctl is-active atlas-source-discovery.service; systemctl is-failed atlas-source-discovery.service 2>/dev/null")
    # how does an approved source get ingested? does source-promote read the catalog?
    out["promote_reads_catalog"]=sh("grep -rlE 'source_catalog|APPROVED|wiring_priority' /opt/atlas/scripts/atlas_source_promote.py /opt/atlas/importers/*promote* /opt/atlas/importers/atlas_socrata*.py /opt/atlas/scripts/atlas_socrata*.py 2>/dev/null | head")
    out["wire_step"]=sh("grep -nE 'recommend|WIRE|wiring|INSERT INTO atlas.so|known_datasets|DATASETS|seed' %s 2>/dev/null | head -12"%F)
    # is there a known-datasets list that source-promote uses (static 60)?
    out["promote_src_list"]=sh("grep -rnE 'DATASETS|known|fxf|fourbyfour|source_catalog|WHERE state' /opt/atlas/scripts/atlas_source_promote.py 2>/dev/null | head -10; ls /opt/atlas/scripts/ 2>/dev/null | grep -iE 'promote|socrata' | head")
except Exception as e: out["error"]=str(e)
def envf(p):
    d={}
    try:
        for ln in open(p):
            ln=ln.strip()
            if ln.startswith('export '): ln=ln[7:]
            if '=' in ln and not ln.startswith('#'):
                k,v=ln.split('=',1); d[k.strip()]=v.strip().strip('"').strip("'")
    except Exception: pass
    return d
try:
    import base64,urllib.request,urllib.error
    env=envf("/etc/atlas/autopull.env"); tok=env.get("STATUS_TOKEN") or os.environ.get("STATUS_TOKEN"); repo=env.get("STATUS_REPO") or "cloudwalker171/atlas-manifests"
    url="https://api.github.com/repos/%s/contents/status/hetzner/discflow.json"%repo; sha=None
    if tok:
        try:
            r=urllib.request.Request(url+"?ref=main",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"}); sha=json.load(urllib.request.urlopen(r,timeout=20)).get("sha")
        except Exception: sha=None
        body={"message":"discflow","content":base64.b64encode(json.dumps(out,indent=2,default=str).encode()).decode(),"branch":"main"}
        if sha: body["sha"]=sha
        for _ in range(6):
            try:
                rq=urllib.request.Request(url,data=json.dumps(body).encode(),method="PUT",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas","Content-Type":"application/json"}); urllib.request.urlopen(rq,timeout=25); break
            except urllib.error.HTTPError as e:
                if e.code==409:
                    try:
                        rq2=urllib.request.Request(url+"?ref=main",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"}); body["sha"]=json.load(urllib.request.urlopen(rq2,timeout=20)).get("sha")
                    except Exception: pass
                else: break
            except Exception: time.sleep(2)
except Exception: pass
sys.exit(0)
